import{_ as t,o as a,c as o,a2 as s}from"./chunks/framework.b3aQeZRM.js";const u=JSON.parse('{"title":"API Compatibility","description":"","frontmatter":{},"headers":[],"relativePath":"api-compatibility.md","filePath":"api-compatibility.md"}'),d={name:"api-compatibility.md"};function i(n,e,r,l,c,p){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="api-compatibility" tabindex="-1">API Compatibility <a class="header-anchor" href="#api-compatibility" aria-label="Permalink to &quot;API Compatibility&quot;">​</a></h1><p>Relay targets practical compatibility for local model servers, not full vendor parity.</p><h2 id="endpoints" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints" aria-label="Permalink to &quot;Endpoints&quot;">​</a></h2><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/</code></td><td>HTML status dashboard (model table, queue, lifecycle)</td></tr><tr><td><code>GET</code></td><td><code>/health</code></td><td>JSON health check (<code>{&quot;ok&quot;:true}</code>)</td></tr></tbody></table><h3 id="openai-compatible" tabindex="-1">OpenAI-compatible <a class="header-anchor" href="#openai-compatible" aria-label="Permalink to &quot;OpenAI-compatible&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/v1/models</code></td><td>List available models with context sizes</td></tr><tr><td><code>GET</code></td><td><code>/v1/models/:model</code></td><td>Get single model metadata</td></tr><tr><td><code>POST</code></td><td><code>/v1/chat/completions</code></td><td>Chat completions (streaming + non-streaming)</td></tr><tr><td><code>POST</code></td><td><code>/v1/completions</code></td><td>Legacy completions shim</td></tr><tr><td><code>POST</code></td><td><code>/v1/responses</code></td><td>OpenAI Responses API</td></tr><tr><td><code>GET</code></td><td><code>/v1/responses/:id</code></td><td>Get stored response</td></tr><tr><td><code>DELETE</code></td><td><code>/v1/responses/:id</code></td><td>Delete stored response</td></tr><tr><td><code>POST</code></td><td><code>/v1/embeddings</code></td><td>Embeddings normalization</td></tr><tr><td><code>POST</code></td><td><code>/v1/rerank</code></td><td>Rerank normalization</td></tr><tr><td><code>POST</code></td><td><code>/rerank</code></td><td>Rerank (alt path)</td></tr></tbody></table><h3 id="anthropic-compatible" tabindex="-1">Anthropic-compatible <a class="header-anchor" href="#anthropic-compatible" aria-label="Permalink to &quot;Anthropic-compatible&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/v1/messages</code></td><td>Anthropic Messages API</td></tr><tr><td><code>POST</code></td><td><code>/v1/messages/count_tokens</code></td><td>Anthropic token counting</td></tr></tbody></table><h3 id="observability" tabindex="-1">Observability <a class="header-anchor" href="#observability" aria-label="Permalink to &quot;Observability&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/relay/status</code></td><td>Full lifecycle + queue JSON</td></tr><tr><td><code>GET</code></td><td><code>/relay/metrics</code></td><td>Request counts, latencies, error rates</td></tr><tr><td><code>GET</code></td><td><code>/relay/jobs</code></td><td>Job queue state</td></tr><tr><td><code>GET</code></td><td><code>/relay/lifecycle</code></td><td>Per-model lifecycle details</td></tr><tr><td><code>GET</code></td><td><code>/relay/stats</code></td><td>Request history</td></tr><tr><td><code>GET</code></td><td><code>/relay/requests</code></td><td>Recent request details</td></tr><tr><td><code>GET</code></td><td><code>/relay/requests/:id</code></td><td>Single request detail</td></tr><tr><td><code>GET</code></td><td><code>/relay/capabilities</code></td><td>Capability registry</td></tr><tr><td><code>POST</code></td><td><code>/relay/capabilities/refresh</code></td><td>Refresh capabilities</td></tr></tbody></table><h2 id="v1-responses-streaming-sse-lifecycle" tabindex="-1"><code>/v1/responses</code> Streaming SSE Lifecycle <a class="header-anchor" href="#v1-responses-streaming-sse-lifecycle" aria-label="Permalink to &quot;\`/v1/responses\` Streaming SSE Lifecycle&quot;">​</a></h2><p>The streaming responses endpoint emits the full OpenAI Responses SSE event sequence:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>response.created → response.in_progress</span></span>
<span class="line"><span>  → response.output_item.added     (message or function_call)</span></span>
<span class="line"><span>    → response.content_part.added   (message only)</span></span>
<span class="line"><span>    → response.output_text.delta    (× N, message only)</span></span>
<span class="line"><span>    → response.function_call_arguments.delta (× N, tool calls)</span></span>
<span class="line"><span>    → response.content_part.done    (message only)</span></span>
<span class="line"><span>    → response.function_call_arguments.done (tool calls)</span></span>
<span class="line"><span>  → response.output_item.done</span></span>
<span class="line"><span>→ response.completed   (or response.failed on error)</span></span></code></pre></div><h3 id="conversation-continuation" tabindex="-1">Conversation Continuation <a class="header-anchor" href="#conversation-continuation" aria-label="Permalink to &quot;Conversation Continuation&quot;">​</a></h3><p><code>/v1/responses</code> supports <code>previous_response_id</code>. Relay stores the full chat message history for each response. When a follow-up request references a previous response, Relay reconstructs the conversation context:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;model&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;qwen3.6-35b-a3b&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;input&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;what about Tokyo?&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;previous_response_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;resp_abc123...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="tool-calls" tabindex="-1">Tool Calls <a class="header-anchor" href="#tool-calls" aria-label="Permalink to &quot;Tool Calls&quot;">​</a></h3><p>Both streaming and non-streaming responses support function tool calls. Non-function tools (web search, file search, code interpreter) are silently stripped since llama.cpp backends don&#39;t support them.</p><h3 id="reasoning-thinking-models" tabindex="-1">Reasoning/Thinking Models <a class="header-anchor" href="#reasoning-thinking-models" aria-label="Permalink to &quot;Reasoning/Thinking Models&quot;">​</a></h3><p>Models that emit <code>reasoning_content</code> (e.g. DeepSeek, Qwen thinking variants) have their reasoning buffered and surfaced as output text when no regular content is generated.</p><h2 id="behavior-notes" tabindex="-1">Behavior Notes <a class="header-anchor" href="#behavior-notes" aria-label="Permalink to &quot;Behavior Notes&quot;">​</a></h2><ul><li>Unknown/hosted-only fields are governed by <code>RELAY_UNKNOWN_FIELD_POLICY</code></li><li>Streaming output is normalized to protocol-appropriate SSE</li><li>Tool calls are normalized across OpenAI and Anthropic shapes</li><li>Error responses use provider-native error shapes (OpenAI or Anthropic)</li><li>Field policies apply per-endpoint: <code>pass_through</code>, <code>strip</code> (with warning), or <code>reject</code></li></ul><h2 id="non-goals" tabindex="-1">Non-Goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-Goals&quot;">​</a></h2><ul><li>Hosted assistants/threads/runs orchestration</li><li>Realtime APIs</li><li>Image/audio/file generation APIs</li><li>Full vendor control-plane semantics</li><li>Batch endpoints</li></ul>`,25)])])}const b=t(d,[["render",i]]);export{u as __pageData,b as default};
